"""
mkt-original layer — Acts chapters 18–19
Output: data/commentary/mkt-original/acts.json
Run: python3 scripts/zc-original-acts-18-19.py

Key translation decisions for this range:
- pneuma (18:5, 25; 19:2, 6, 12, 13, 15, 16, 21): 'Spirit' when referring to the Holy Spirit;
  18:5 has a textual variant — 'constrained by the Spirit' vs 'pressed in the word'; the MKT
  follows 'Spirit' (pneumati) as the better-attested reading; 19:12 pneuma = evil spirits (not
  Holy Spirit — context determines)
- logos (18:11, 15; 19:10, 20, 38, 40): 'word' in gospel-proclamation contexts; 'matter/case'
  in the legal contexts of 18:15 and 19:38; 'account/reason' in 19:40
- nomos (18:13, 15): 'law' — the Jewish Torah, not Roman lex; Gallio distinguishes these
- charis (18:27): 'grace' — divine favor enabling Apollos's ministry in Achaia
- theos (multiple): 'God' throughout — capitalized; the disp=2 reflects the lexical range
  (Greek theos can = a deity generically) but in Acts the referent is consistently YHWH/the
  Father; 19:26 ('gods made with hands') uses the lower-case generic sense
- hagios (19:2, 6): 'Holy' — 'Holy Spirit' consistently capitalized in MKT; disp=2 notes
  ceremonial/moral ambiguity of hagios but the compound pneuma hagion = Holy Spirit throughout
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ACTS_CH18_19 = {
"18": {
"1": "<p>'After this Paul left Athens and went to Corinth' — the departure from Athens ends the Areopagus mission (17:16-34) and begins the eighteen-month Corinthian ministry. The transition marks a strategic shift: Corinth is a commercial crossroads, not an intellectual center; Paul's subsequent letters reveal that his Corinthian preaching deliberately avoided rhetorical display (1 Cor 2:1-4). The Athens-to-Corinth movement also corresponds to a shift from the philosophical register of 17:22-31 to the cross-centered proclamation of 1 Cor 1:23.</p>",
"2": "<p>'A Jew named Aquila, a native of Pontus, who had recently come from Italy with his wife Priscilla, because Claudius had ordered all Jews to leave Rome' — the expulsion under Claudius (ca. 49-50 AD) is corroborated by Suetonius (Claudius 25.4 — 'Since the Jews constantly made disturbances at the instigation of Chrestus, he expelled them from Rome'). 'Chrestus' is likely 'Christus' — the dispute over the messianic claims of Jesus was splitting Roman synagogues. Aquila and Priscilla are likely already believers when Paul meets them; their synagogue dispute would explain their expulsion alongside other Jewish Christians.</p>",
"3": "<p>'Because he was a tentmaker as they were, he stayed and worked with them' — skēnopoios (tentmaker, leather-worker) is Paul's trade, consistent with his manual-labor principle (1 Thess 2:9; 1 Cor 9:12-15; 2 Thess 3:8). The philosophical tradition required teachers to receive fees; Paul's refusal to take support from Corinth (2 Cor 11:7-9) was a deliberate counter-convention: the teacher who works with his hands is not a sophist selling wisdom. The trade-based friendship with Aquila and Priscilla becomes one of the most enduring partnerships of Paul's ministry.</p>",
"4": "<p>'Every Sabbath he reasoned (dielēgeto — was dialoguing/disputing) in the synagogue, trying to persuade Jews and Greeks' — dielēgeto (imperfect = ongoing, repeated action) is the characteristic Lukan verb for Paul's synagogue method: not monologue proclamation but dialogical reasoning. 'Persuade' (epeithein — to persuade, imperfect = kept attempting) combined with dielēgeto creates the portrait of a reasoned, interactive theological engagement. 'Jews and Greeks' — the synagogue's Gentile adherents (sebomenoi — God-fearers) are included in Paul's audience from the beginning of the Corinthian synagogue phase.</p>",
"5": "<p>'When Silas and Timothy came from Macedonia, Paul devoted himself exclusively to preaching (syneicheto tō logō — was constrained/pressed by the word), testifying to the Jews that Jesus was the Messiah' — the textual tradition at syneicheto offers two readings: some MSS read tō logō (by the word) and others tō pneumati (by the Spirit, disp=3); the MKT follows 'Spirit' as primary. The arrival of Silas and Timothy (with financial support from Macedonian churches — 2 Cor 11:8-9) freed Paul from tentmaking, enabling full-time proclamation. 'Testifying that Jesus was the Messiah' — the content: the specific claim that Jesus of Nazareth is the Christ (ton Christon einai Iēsoun) is the central Jewish stumbling block.</p>",
"6": "<p>'When they opposed Paul and became abusive, he shook out his clothes in protest and said, Your blood be on your own heads!' — the symbolic action (ektinaxamenos ta himatia — shaking out the garments) echoes Nehemiah's curse-gesture (Neh 5:13 — 'I shook out the fold of my garment') and is the escalated form of the dust-shaking from feet (Acts 13:51). 'Your blood be on your own heads' — the blood-guilt formula draws on Ezek 33:4-5: if the watchman warns and the people do not hear, 'his blood shall be on his own head.' Paul has fulfilled his prophetic-watchman duty; the guilt for rejection now belongs to the rejectors. 'I am innocent; from now on I will go to the Gentiles' — the Gentile-turn formula repeated from 13:46.</p>",
"7": "<p>'Paul went to the house of Titius Justus, a worshipper of God (sebomenou ton theon — one fearing/revering God)' — the God-fearer designation (sebomenos) marks Titius Justus as a Gentile synagogue-adherent: he has adopted monotheism and Jewish ethics but is uncircumcised. His house is strategically located 'next door to the synagogue' — Paul's Gentile base of operations is literally adjacent to the Jewish community he has just left. The geographical irony (the synagogue's Gentile neighbors receive what the synagogue rejected) is characteristic of Luke's narrative theology.</p>",
"8": "<p>'Crispus, the synagogue leader (archisynagōgos), and his entire household believed in the Lord; and many of the Corinthians who heard Paul believed and were baptised' — Crispus's conversion is corroborated by 1 Cor 1:14 (Paul baptised Crispus himself, one of the very few he personally baptised). The synagogue leader's conversion is the highest-profile loss the Corinthian Jewish community sustained. 'His entire household believed' — the household-unit conversion pattern consistent throughout Acts. 'Many of the Corinthians' — the city's general population begins to respond beyond the synagogue community.</p>",
"9": "<p>'One night the Lord spoke to Paul in a vision: Do not be afraid; keep on speaking, do not be silent' — the Lord's vision (en horamati — in a vision) uses the standard prophetic-vision vocabulary (horama: Acts 10:3; 16:9; 18:9). The double negative command (mē phobou, mē siōpēsēs — do not fear, do not be silent) addresses two temptations that would naturally follow synagogue opposition: fear of violence and the temptation to withdraw. The night timing and visionary form (as opposed to waking auditory experience) is the standard divine-warning vehicle (Gen 26:24; 46:2-3; 1 Kgs 3:5).</p>",
"10": "<p>'For I am with you, and no one is going to attack and harm you, because I have many people in this city' — 'I am with you' (egō eimi meta sou) is the divine-presence formula used at commissioning moments throughout the OT (Exod 3:12; Josh 1:5, 9; Jer 1:8, 19) — the Emmanuel-formula. 'I have many people in this city' (laos estin moi polys en tē polei tautē) — the divine claim over Corinth before they have converted: God's elect in Corinth are already his people who have not yet heard. The vision explains why Paul must not be silent: there is a harvest already prepared.</p>",
"11": "<p>'So Paul stayed in Corinth for a year and a half, teaching them the word of God' (logon tou theou — the word of God; disp=3 for logos) — the eighteen months (eniayton kai mēnas hax) is the longest fixed-duration stay Luke records in the second missionary journey. 'The word of God' as logos is the gospel-proclamation content: the message that Paul teaches is identified as God's own word. The long stay corresponds to the Lord's vision-promise: God has people here, so Paul must preach long enough to find them all.</p>",
"12": "<p>'While Gallio was proconsul (anthypatos) of Achaia, the Jews of Corinth made a united attack on Paul and brought him to the place of judgment (bēma — tribunal/judgment seat)' — Gallio's proconsulate is dateable from the Delphi Inscription (ca. 51-52 AD), providing one of the firmest chronological anchors for Pauline chronology. The bēma (raised judicial platform) is the same word used for God's judgment seat (Rom 14:10; 2 Cor 5:10) — Luke's placement of Paul before an earthly bēma prefigures the cosmic bēma before which all will appear.</p>",
"13": "<p>'This man is persuading the people to worship God in ways contrary to the law (para ton nomon — contrary to the law)' — the charge is deliberately ambiguous: para ton nomon could refer to the Jewish Torah or Roman law. The Jewish accusers probably intend the Torah (Paul's messianic preaching disrupts Jewish worship patterns); Gallio will interpret the charge as referring to internal Jewish disputes (v.15). The nomos (disp=3) here is the Jewish Law — the word that governs the covenant community's religious practice.</p>",
"14": "<p>'If you Jews were making a complaint about some misdemeanour or serious crime (adikēma ti ē rhadiourgēma ponēron), it would be reasonable for me to listen to you' — Gallio distinguishes between actionable legal offenses (adikēma: a wrong done; rhadiourgēma ponēron: a vicious/serious villainy) and matters of Jewish internal dispute. His willingness to hear genuine criminal complaints (v.14) vs. his refusal to adjudicate religious questions (v.15) establishes the legal precedent that Paul's movement does not constitute a Roman criminal offense.</p>",
"15": "<p>'But since it involves questions about words and names and your own law (tou nomou hymōn — your own law), settle the matter yourselves. I will not be a judge of such things' — Gallio identifies the dispute as involving logos (disp=3 — 'words': the meaning of terms), onomata (names: the identity-claim about Jesus as Messiah), and nomos (disp=3 — 'your law': internal Jewish legal interpretation). All three belong to Jewish internal discourse; Roman magistrates have no jurisdiction over theological disputes. The Gallio ruling implicitly classifies Christianity as an intra-Jewish matter, providing de facto legal protection for the early mission.</p>",
"16": "<p>'So he drove them off (apēlasen autous — dismissed/drove them away)' — Gallio's dismissal (apēlasen, aorist of apelaunō — to drive/push away) is abrupt and decisive. The proconsul exercises his authority to clear his tribunal of cases that do not belong to it. The brevity of the verse mirrors the brevity of Gallio's engagement: he considers the matter not worth his attention, and says so by action rather than extended argument.</p>",
"17": "<p>'Then the crowd seized Sosthenes the synagogue leader and beat him in front of the proconsul; and Gallio showed no concern whatever' — the beating of Sosthenes (etypton — kept striking, imperfect) by 'the crowd' is ambiguous: some MSS specify 'the Greeks,' suggesting a spontaneous anti-Jewish action by the Corinthian populace seizing on Gallio's dismissal as permission for mob violence. Gallio's indifference (ouden toutōn tō Galliōni emelen — none of these things concerned Gallio) is the Roman administrator's calculated non-intervention in non-Roman affairs. Sosthenes may be the same person addressed in 1 Cor 1:1 as co-sender — perhaps his persecution became the occasion of his conversion.</p>",
"18": "<p>'Paul stayed on in Corinth for some time. Then he left the brothers and sisters and sailed for Syria, accompanied by Priscilla and Aquila. Before he sailed, he had his hair cut off at Cenchreae because of a vow he had made' — the hair-cutting (keiramenos tēn kephalēn) at Cenchreae (Corinth's eastern port) is a Nazirite vow-completion gesture (Num 6:18 — the Nazirite shaves his head at the vow's end). Paul observes Torah practices alongside his proclamation of freedom from the Law — the consistency with the Jerusalem council's decision (15:19-21) and his own principle of becoming 'all things to all people' (1 Cor 9:20-22). Priscilla and Aquila's inclusion in the travel party marks them as full partners in the mission.</p>",
"19": "<p>'They arrived at Ephesus, where Paul left Priscilla and Aquila. He himself went into the synagogue and reasoned with the Jews' — the Ephesus stop is brief (v.20-21 — he declines to stay longer despite their invitation) but strategically significant: Paul establishes the initial synagogue contact (dielexato — he dialogued/reasoned) and leaves Priscilla and Aquila as his representatives. Their presence in Ephesus will be decisive for Apollos's correction (v.26). Paul's synagogue entry before his departure plants the seed that his extended return will cultivate (19:1-10).</p>",
"20": "<p>'When they asked him to spend more time with them, he declined' — the Ephesians' invitation (erōtōntōn autōn — they were asking/requesting, imperfect = continued asking) and Paul's refusal (ouk epeneusen — he did not nod assent) creates a reversal of the Macedonian vision pattern (16:9 — 'come over and help us'): here the Gentiles plead for more time and Paul says no. His haste to return to Jerusalem and Antioch (v.21-22) is the controlling factor. The Ephesian receptivity makes the brevity of this first visit rhetorically effective — their longing for more sets up the extended ministry of 19:1-10.</p>",
"21": "<p>'But as he left, he promised, I will come back if it is God's will (tou theou thelontos — if God wills)' — the conditional 'if God wills' (the deo voluntate formula) is Paul's standard acknowledgment that itinerary is divinely governed (Rom 1:10; 15:32; 1 Cor 4:19; 16:7; Jas 4:13-15). The promise is not merely polite; it is the expression of the missionary's dependence on divine direction. The promise is fulfilled in 19:1 — Paul returns to Ephesus via the interior route.</p>",
"22": "<p>'When he landed at Caesarea, he went up to Jerusalem and greeted the church and then went down to Antioch' — 'went up to Jerusalem' (anabas) and 'went down to Antioch' (katebē) use the standard Palestinian topographical verbs: Jerusalem is always anabainō (go up) regardless of compass direction — it is elevated both geographically and in religious significance. The 'greeting the church' (aspásamenos tēn ekklēsian) is a rapid visit, not an extended stay; Paul's third missionary journey begins immediately (v.23).</p>",
"23": "<p>'After spending some time in Antioch, Paul set out from there and travelled from place to place throughout the region of Galatia and Phrygia, strengthening all the disciples' — the 'region of Galatia and Phrygia' (tēn Galatikēn chōran kai Phrygian — Galatian region and Phrygian region) is the interior route that bypasses the coast before arriving at Ephesus (19:1). 'Strengthening (epistērizōn — making stable/firm) all the disciples' — the participle establishes the purpose of the journey: not evangelism but consolidation and follow-up of existing communities planted in the second journey.</p>",
"24": "<p>'A Jew named Apollos, a native of Alexandria, came to Ephesus. He was a learned man (anēr logios — a word-skilled/eloquent man), with a thorough knowledge (dynastatos — powerful) of the Scriptures' — Alexandria was the intellectual capital of the diaspora, home of the LXX translation and the Jewish philosophical tradition (Philo). Logios (word-skilled, eloquent) is the highest compliment for a rhetorical culture: Apollos is both eloquent in speech and learned in content. 'Thorough knowledge (dynastatos — capable/powerful) in the Scriptures' — his power is textual competence; he can demonstrate from the Hebrew Bible. 1 Cor 1:12 and 3:4-6 show that Apollos became a significant figure at Corinth.</p>",
"25": "<p>'He had been instructed in the way of the Lord, and he spoke with great fervour (zeōn tō pneumati — boiling/fervent in spirit; disp=3 for pneuma) and taught about Jesus accurately, though he knew only the baptism of John' — zeōn tō pneumati (boiling/fervent in spirit) — pneuma here may refer to Apollos's own spirit (human fervor) rather than the Holy Spirit; the MKT 'great fervour' preserves the ambiguity. The irony: Apollos teaches accurately about Jesus (akribōs — precisely, carefully) but knows only John's preparatory baptism, not the post-resurrection baptism in Jesus's name. His accurate-but-incomplete knowledge is the occasion for Priscilla and Aquila's correction.</p>",
"26": "<p>'He began to speak boldly in the synagogue. When Priscilla and Aquila heard him, they invited him to their home and explained to him the way of God (tēn tou theou hodon — the way of God; disp=2 for theos) more adequately (akribesteron — more precisely/accurately)' — the correction of Apollos by Priscilla and Aquila is notable: Priscilla is named first (v.2, 18, 26 — the majority of references put her before Aquila), suggesting she was the more prominent teacher. The private setting ('invited him to their home') and the term akribesteron (more accurately — comparative of the same akribōs used for Apollos's teaching in v.25) show that the correction is gentle and precise: not a rebuke but an extension of what Apollos already knows.</p>",
"27": "<p>'When Apollos wanted to go to Achaia, the brothers and sisters encouraged him and wrote to the disciples there to welcome him. When he arrived, he was a great help to those who by grace (dia tēs charitos — through grace; disp=2 for charis) had believed' — charis (grace) here denotes the divine enabling-favor that produced the Achaian believers' faith: they believed 'through grace' — not by their own capacity but by God's gift (Eph 2:8-9). Apollos's role is strengthening those already converted by Paul's mission: he waters what Paul planted (1 Cor 3:6). The letter of recommendation (the 'brothers and sisters encouraged him and wrote') is the earliest instance of a NT letter of commendation (cf. 2 Cor 3:1-2).</p>",
"28": "<p>'He vigorously refuted (diakatelenchteto — thoroughly confuted/convicted) his Jewish opponents in public debate, proving from the Scriptures that Jesus was the Messiah (ton Christon einai Iēsoun)' — diakatelenchteto (imperfect = continued/repeated refutation) is a compound intensive: he was thoroughly and continuously defeating his opponents in argument. 'Proving from the Scriptures' (epideiknys dia tōn graphōn — showing through the writings) is the standard apostolic demonstration-method: the case for Jesus's messiahship is made from the Hebrew Bible itself, not from apostolic authority alone. Apollos's Alexandrian education makes him the most scripture-literate debater the early mission produced.</p>"
},
"19": {
"1": "<p>'While Apollos was at Corinth, Paul took the road through the interior (ta anōterika merē — the upper/inland regions) and arrived at Ephesus. There he found some disciples' — the 'upper regions' route (through Galatia and Phrygia — 18:23) bypasses Ephesus's coastal approach; Paul arrives from the interior, not by sea. The 'disciples' (mathētas — learners/disciples) he finds are identifiable as believers but will prove to have received only John's baptism (v.3). Luke uses 'disciples' as the standard term for Christians; the word prepares the reader to be surprised when their pneumatological deficiency is revealed.</p>",
"2": "<p>'Did you receive the Holy Spirit when you believed?' — the aorist participle pisteusantes (when you believed) links Spirit-reception to the moment of faith. The disciples' answer ('We have not even heard that there is a Holy Spirit') is not ignorance of the Spirit's existence (the Spirit pervades OT scripture) but ignorance of the Pentecostal gift: the outpouring of the Spirit as the mark of the messianic age (Joel 2:28-32). 'Holy Spirit' (pneuma hagion, disp=3 for pneuma, disp=2 for hagios) — the compound term is the distinctive NT designation for the third person as the gift of the messianic era; the Ephesian disciples have not heard of this specific Pentecostal-fulfillment gift.</p>",
"3": "<p>'Then what baptism did you receive? John's baptism, they replied' — the clarifying question and answer identifies the Ephesian disciples as followers of John the Baptist's preparatory movement. John's baptism was 'for repentance' (v.4 — eis metanoian) but pointed forward to the 'one coming after' who would baptize 'with the Holy Spirit and fire' (Matt 3:11). These disciples received the repentance-baptism but not the Spirit-baptism that the one John pointed to has now given. Their incomplete initiation mirrors Apollos's incomplete knowledge (18:25) — the Johannine stream needs completion in the Spirit-baptism of the messianic age.</p>",
"4": "<p>'John's baptism was a baptism of repentance (eis metanoian — unto repentance). He told the people to believe in the one coming after him, that is, in Jesus' — Paul's explanation identifies John's own testimony as self-referential and forward-pointing: John's baptism was never an end in itself but was designed to create readiness for the one following. 'Believe in the one coming after him, that is, in Jesus' — the tina formula ('the one coming') is John's own messianic designation; Paul identifies the referent as Jesus. John's ministry is validated by its completion in Jesus, not replaced by it.</p>",
"5": "<p>'On hearing this, they were baptised in the name of the Lord Jesus' — the immediate response (eis to onoma tou Kyriou Iēsou — into the name of the Lord Jesus) uses the same formula as the Cornelius baptism (10:48). The sequence — hearing, believing, baptism — is the standard Acts conversion pattern. The 'name' (onoma) into which they are baptised is the authority-realm: baptism in Jesus's name means being placed under his lordship and entering the community constituted by his name.</p>",
"6": "<p>'When Paul placed his hands on them (epithentos autois tou Paulou tas cheiras), the Holy Spirit came on them, and they spoke in tongues and prophesied' — the laying on of hands as the physical accompaniment of Spirit-reception appears also in 8:17 (Peter and John in Samaria). 'The Holy Spirit came on them' (ēlthen to pneuma to hagion ep' autous — the Holy Spirit came upon them; disp=3 for pneuma, disp=2 for hagios) — the same construction as the Acts 2 and Acts 10 Pentecosts. The twin signs (tongues and prophecy) are the Pentecost-signs; the Ephesian episode is a third Pentecost, extending the Spirit's geographic reach to Asia. The three Pentecosts — Jerusalem (ch 2), Caesarea (ch 10), and now Ephesus — form a pattern of Spirit-outpouring that progressively fills the world.</p>",
"7": "<p>'There were about twelve men in all' — the number twelve (andres hōsei dōdeka — about twelve men) is almost certainly not coincidental: twelve is the number of Israel's tribes and the number of the apostles chosen as the reconstituted Israel (Luke 6:13-16). The Ephesian Twelve recall the original Twelve — a second Pentecost-founding of a community that mirrors the Jerusalem community's apostolic nucleus. Luke's near-certainty ('about twelve') maintains his characteristic concern for precision while acknowledging approximation.</p>",
"8": "<p>'Paul entered the synagogue and spoke boldly there for three months, arguing persuasively (peithōn — persuading, present participle = ongoing persuasion) about the kingdom of God' — the three-month synagogue phase follows the same pattern as every previous city: the synagogue first. 'Kingdom of God' (tēn basileian tou theou — the kingdom of God; disp=2 for theos) is Paul's Ephesian preaching content: the eschatological reign of God announced in Jesus. 'Boldly' (parrēsiazomenos — speaking with freedom/boldness) — parrēsia is the characteristic apostolic speech-quality that the Holy Spirit produces (4:31).</p>",
"9": "<p>'Some of them became obstinate; they refused to believe and publicly maligned the Way (tēn hodon — the Way). So Paul left them. He took the disciples with him and had discussions daily in the lecture hall of Tyrannus' — 'the Way' (hē hodos) is the earliest self-designation of the Jesus movement (Acts 9:2; 19:9, 23; 22:4; 24:14, 22); it echoes Isaiah's 'prepare the way of the LORD' (Isa 40:3) and Jesus's self-description as 'the Way' (John 14:6). The Tyrannus school (scholē — a place of leisure and learning) is Paul's Gentile-space alternative to the synagogue: a neutral intellectual venue that expands the audience beyond synagogue-adherents.</p>",
"10": "<p>'This went on for two years, so that all the Jews and Greeks who lived in the province of Asia heard the word of the Lord (ton logon tou Kyriou — the word of the Lord; disp=3 for logos)' — the two-year duration (epi etē dyo — for two years) in Ephesus is Paul's longest recorded stay; it produces the greatest geographic reach: 'all the Jews and Greeks who lived in Asia' — the entire province evangelized from a single city center. The house-church network that Paul's teaching produces (cf. the letters to the Colossians, Laodiceans, and Philemon) demonstrates that the Ephesian school functions as a training and sending center.</p>",
"11": "<p>'God did extraordinary miracles through Paul (dynameis ou tas tychousas ho theos epoiei dia tōn cheirōn Paulou — not the ordinary/common miracles)' — ou tas tychousas (not the ones that happen by chance/not ordinary) is a litotes (understatement that affirms by negation): these were not common miracles but exceptional ones. 'Through the hands of Paul' — the instrumental mediation through Paul's physical person is emphasized; the power is God's, the channel is Paul. The contrast with the seven sons of Sceva (v.13-16) will sharpen: Paul's miracles work because God works through him; the exorcists' invocations fail because Jesus does not know them.</p>",
"12": "<p>'So that even handkerchiefs and aprons that had touched him were taken to those who were ill, and their illnesses were cured and the evil spirits (ta pneumata ta ponēra — the evil spirits; disp=3 for pneuma) left them' — the fabric-contact healing (soudarion = sweat-cloth; simikinthion = apron) parallels Peter's shadow-healing (5:15-16): physical proximity to the apostle as a channel of divine power. The 'evil spirits' (pneumata ponēra) that leave the afflicted are the same pneumata that the Sceva sons (v.13) will unsuccessfully attempt to command — the contrast between genuine Spirit-empowered healing and imitative religious practice is the narrative's point.</p>",
"13": "<p>'Some Jews who went around driving out evil spirits tried to invoke the name of the Lord Jesus over those who were demon-possessed. They would say, In the name of the Jesus whom Paul preaches (hon Paulos kērussei), I command you' — the Jewish exorcists (exorkistōn — exorcists, a technical term for the profession) are itinerant practitioners of spirit-expulsion — a recognized occupation in both Jewish and Hellenistic worlds. Their use of 'Jesus' as a power-word follows the magical-name principle: the name of a demonstrated wonder-worker was borrowed for invocations. 'The Jesus whom Paul preaches' — the indirect relationship reveals the problem: they know Jesus as Paul's subject, not as their Lord.</p>",
"14": "<p>'Seven sons of Sceva, a Jewish chief priest (archiereōs — chief/high priest), were doing this' — the 'Jewish chief priest' Sceva is otherwise unattested in high-priestly records; 'chief priest' (archiereus) may be an honorific self-claim rather than an official title, or Sceva is a diaspora figure of priestly descent. 'Seven sons' — the number seven (hepta) may intend the sense of completeness: a full family of exorcistic practitioners. The family's collective failure to control a single demon-possessed man will make the point decisively.</p>",
"15": "<p>'One day the evil spirit answered them: Jesus I know (ginōskō), and Paul I know about (epistamai), but who are you?' — the spirit's response uses two different verbs: ginōskō (know by acquaintance, personal knowledge — for Jesus) and epistamai (know about by learning/hearsay — for Paul). The spirit's direct personal knowledge of Jesus and indirect informational knowledge of Paul versus its total ignorance of the Sceva sons reveals the hierarchy of authority: Jesus is known intimately as the supreme power; Paul is known as Jesus's authorized agent; the Sceva sons are unknown because they have no authorization. The pneuma (disp=3) here is the evil/unclean spirit, not the Holy Spirit.</p>",
"16": "<p>'Then the man who had the evil spirit jumped on them and overpowered them all. He gave them such a beating that they ran out of the house naked and bleeding' — the single demon-possessed man overpowering all seven sons is a comic-terrible scene: the unauthorized name-invokers are physically defeated by the very power they tried to command. The nakedness (gymnous) and wounds (tetragmatismenous — wounded/battered) are the marks of shameful defeat; the running away completes the reversal of power. The scene demonstrates that spiritual authority is not transferred by name-borrowing but by personal relationship with the Named One.</p>",
"17": "<p>'When this became known to the Jews and Greeks living in Ephesus, they were all seized with fear, and the name of the Lord Jesus was held in high honour (emegalyneto to onoma tou Kyriou Iēsou — the name of the Lord Jesus was being magnified)' — megalynō (to magnify/enlarge/hold great) is Mary's verb in the Magnificat (Luke 1:46 — 'my soul magnifies the Lord'). The community's fear (phobos epepesen epi pantas — fear fell upon all) is the same theophanic-fear that accompanies divine power manifestations (2:43; 5:11). The result of the Sceva disaster is not discrediting Jesus's name but elevating it: the failure of unauthorized use demonstrates the name's genuine power.</p>",
"18": "<p>'Many of those who believed now came and openly confessed what they had done (exomologoumenoi kai anangellontes tas praxeis autōn — confessing and announcing their deeds)' — the combination of exomologeomai (to confess fully, to acknowledge openly — the standard confession-word) and anangellō (to report, announce, declare) indicates public disclosure rather than private confession. 'Those who had believed' (pepisteukotōn — perfect participle: those who had come to belief and remain in it) includes people who maintained secret magical practices alongside their Christian profession. The revival produces the honesty that genuine repentance requires.</p>",
"19": "<p>'A number who had practised sorcery brought their scrolls together and burned them publicly. When they calculated the value of the scrolls, the total came to fifty thousand drachmas' — the magic scrolls (ta biblia — the books, the scrolls) were the written formulas, incantations, and binding spells of the Ephesian magical tradition; 'Ephesian letters' (Ephesia grammata) was the technical term in antiquity for a category of magical texts. Fifty thousand drachmas — fifty thousand days' wages for an ordinary worker — is the monetary statement of what was surrendered. The public burning (katekaion — they were burning, imperfect = ongoing, public action) rather than private disposal demonstrates the total repudiation of the previous practice.</p>",
"20": "<p>'In this way the word of the Lord spread widely and grew in power (houtōs kata kratos ho logos tou Kyriou ēuxanen kai ischyen — so with power the word of the Lord kept growing and prevailing; disp=3 for logos)' — kata kratos (according to strength, with might/power) is the intensive formula for the gospel's advance against resistance. The word (logos as proclamation-content) is the subject of both verbs: it grew (ēuxanen) and prevailed (ischyen) — the word itself is the active agent, not merely the medium. The Ephesian revival — Spirit-baptism, extraordinary healings, failed exorcism, mass confession, public book-burning — culminates in this summary of the word's victorious expansion.</p>",
"21": "<p>'After all this had happened, Paul resolved in the Spirit (etheto... en tō pneumati — he purposed in the Spirit; disp=3 for pneuma) to go to Jerusalem, passing through Macedonia and Achaia' — etheto en tō pneumati (he purposed/set in the Spirit) — the pneuma here may refer to Paul's own spirit (his own decision-faculty) or the Holy Spirit's direction; the MKT 'decided' opts for the ambiguity-resolving human-decision reading. The itinerary (Macedonia → Achaia → Jerusalem → Rome) is the structural arc of the rest of Acts: Paul's Spirit-purposed Jerusalem visit will end in his arrest (21:27-36) and his Rome arrival will end the book (28:30-31).</p>",
"22": "<p>'He sent two of his helpers, Timothy and Erastus, to Macedonia, while he stayed in the province of Asia a little longer' — Timothy (Paul's closest co-worker, named in every major Pauline letter) and Erastus (possibly the city treasurer of Corinth, Rom 16:23; 2 Tim 4:20) are sent as advance representatives. Paul's remaining in Asia 'a little longer' (epi chronon — for a time) before the Demetrius riot erupts suggests that his departure was imminent anyway; the riot accelerates his timeline. The sending of representatives while remaining himself is Paul's characteristic apostolic delegation.</p>",
"23": "<p>'About that time there arose a great disturbance about the Way (peri tēs hodou — concerning the Way)' — 'the Way' (hē hodos) as the Jesus movement's self-designation appears here in the context of its first major civic persecution at Ephesus. The disturbance (tarachos — tumult, confusion, disorder) is significant: not synagogue opposition but a trade-guild economic grievance that has become a civic crisis. The gospel's penetration of Ephesian society has reached the point where it threatens a major local industry.</p>",
"24": "<p>'A silversmith named Demetrius, who made silver shrines of Artemis, brought in a lot of business for the craftsmen there' — Demetrius is a silversmith (argurokópos) who manufactures naiskoi (silver shrines) of Artemis — the portable votive miniatures of the Artemision that pilgrims purchased and offered. Artemis of Ephesus was not the Greek Artemis (huntress/moon goddess) but a distinctively Anatolian fertility deity whose great temple at Ephesus was one of the seven wonders of the ancient world. The trade was substantial: the Artemision attracted pilgrims from across the Mediterranean.</p>",
"25": "<p>'You know, my friends, that we receive a good income from this business' — Demetrius's first appeal is purely economic: 'we receive a good income' (hē eudaiporia... estin hēmin — our prosperity/wellbeing is from this). The economic argument precedes the religious argument: his audience are craftsmen who will respond first to the threat to their livelihood. The religious justification (v.27 — the Artemis cult) comes second — it amplifies economic grievance with religious outrage and civic pride, producing a combustible mixture.</p>",
"26": "<p>'This fellow Paul has convinced and led astray large numbers of people here in Ephesus and in practically the whole province of Asia. He says that gods made by human hands (hoi cheiropoiētoi — handmade gods) are no gods at all' — cheiropoiētoi (made-by-hands) is the prophetic-polemic vocabulary used by Isaiah against idols (Isa 46:6 LXX); the LXX uses cheiropoiētoi consistently for man-made images. Demetrius accurately summarizes Paul's monotheistic preaching: what the hands make cannot be god. The irony of Demetrius's formulation — a man who makes gods-by-hands complaining that Paul calls them handmade — is precisely Paul's point. 'Practically the whole province of Asia' confirms the scope of 19:10.</p>",
"27": "<p>'There is danger not only that our trade will lose its good name, but also that the temple of the great goddess Artemis will be discredited; and the goddess herself, who is worshipped throughout the province of Asia and the world, will be robbed of her divine majesty' — Demetrius escalates from trade-loss to religious offense to universal implications: the Artemision's status as a pan-Mediterranean sanctuary gives his argument its maximum emotional force. The three-level escalation (our business → the temple → the goddess herself) mirrors the three-level structure of his audience's loyalty: they are craftsmen, Ephesians, and devotees of Artemis. Each level is threatened.</p>",
"28": "<p>'When they heard this, they were furious and began shouting: Great is Artemis of the Ephesians! (Megalē hē Artemis Ephesiōn)' — the liturgical shout (Megalē... — Great is...) is not spontaneous but draws on the established cultic acclamation-form used at Artemis festivals. The fury (thumou — passionate anger, passion) + liturgical cry combination produces the religious riot: the crowd's economic anxiety has been successfully translated into religious fervor by Demetrius's speech. Two hours of chanting (v.34) demonstrates the depth of the civic-religious identity at stake.</p>",
"29": "<p>'Soon the whole city was in an uproar. The people seized Gaius and Aristarchus, Paul's travelling companions from Macedonia, and all rushed into the theatre together' — the theatre (theatron) of Ephesus seated approximately 24,000 people; it was the standard venue for civic assemblies (v.39 — legal ekklēsia) and the largest public space available for the mob's spontaneous action. Gaius (cf. Rom 16:23; 1 Cor 1:14) and Aristarchus (cf. Acts 20:4; 27:2; Col 4:10; Phlm 24) are Macedonians traveling with Paul — their seizure targets Paul's known associates when Paul himself is inaccessible.</p>",
"30": "<p>'Paul wanted to appear before the crowd, but the disciples would not let him' — the disciples' restraint of Paul (ouk eiōn auton hoi mathētai — the disciples kept not allowing him) is an imperfect of repeated prevention: they kept stopping him. Paul's desire to enter the assembly is consistent with his general pattern of engaging opposition directly (17:17; 19:8); the disciples' restraint is pastoral protection. The disciples have calculated that Paul's appearance would escalate rather than resolve the situation.</p>",
"31": "<p>'Even some of the officials of the province (asiarchōn — Asiarchs), friends of Paul, sent him a message begging him not to venture into the theatre' — the Asiarchs were the leading citizens of Asia, elected to preside over the imperial cult festivals and provincial assemblies — essentially the regional aristocracy. Their friendship with Paul (ōsin autō philoi — were his friends) demonstrates that Paul's ministry penetrated Ephesian upper society; their warning through private messengers shows that even allies of Paul outside the church recognized the danger. The plural 'friends' (philoi) implies established relationships, not casual acquaintance.</p>",
"32": "<p>'The assembly was in confusion: some were shouting one thing, some another. Most of the people did not even know why they were there' — Luke's summary of the assembly is darkly comic: oi men... oi de (some... others) were shouting different things, and the majority (hoi pleious) did not know the reason for the gathering (tinos heneken synelēlytheisan — for what purpose they had come together). The mob has its own momentum, independent of any coherent purpose. The chaos is the point: the threat to the gospel is a riot built on ignorance, not a reasoned persecution.</p>",
"33": "<p>'The Jews in the crowd pushed Alexander to the front, and they shouted instructions to him. He motioned for silence in order to make a defence (apologeisthai — to make a defense/apologia) before the people' — Alexander's identity is uncertain: possibly a Jewish spokesman attempting to distance the Jewish community from the Christian agitators, or a Christian named Alexander. The Jews' pushing him forward suggests they wanted to disassociate Judaism from the gospel movement (which would otherwise be identified as a Jewish sect). His attempt at apologia (the formal legal defense speech) is immediately shut down by the crowd's recognition that he is Jewish.</p>",
"34": "<p>'But when they realised he was a Jew, they all shouted in unison for about two hours: Great is Artemis of the Ephesians!' — the two-hour chant (epi hōras dyo — for about two hours) is a remarkable demonstration of the crowd's sustained religious passion. The recognition of Alexander's Jewishness triggers the chant: Jewish monotheism and the Artemis cult are antithetical; the crowd correctly identifies the Jewish theological position as equally hostile to their goddess as the Christian one. The unified liturgical chant excludes both Jews and Christians.</p>",
"35": "<p>'The city clerk (grammateus — secretary/clerk) quietened the crowd and said: Fellow Ephesians, doesn't all the world know that the city of Ephesus is the guardian (neōkoron — temple warden) of the temple of the great Artemis?' — the grammateus (city clerk) was the most important civic official in Ephesus, responsible for official communications with Rome. His calming intervention is authoritative and pragmatic. 'Neōkoron' (temple warden) was an official title of honor given to cities that hosted imperial or divine cult; Ephesus held this status for Artemis. The clerk's appeal to established fact (the world already knows) defuses the anxious assertion: there is nothing to prove by rioting.</p>",
"36": "<p>'Therefore, since these facts are undeniable (anantirrhētōn — cannot-be-contradicted), you ought to calm down and not do anything rash' — anantirrhēton (undeniable, incapable of being spoken against) is a legal/rhetorical term: the clerk uses forensic vocabulary to reframe the riot as an unnecessary and legally dangerous overreaction to a settled fact. 'Calm down' (katastalmenos hyparchein — to be composed/settled) is the imperative of dignified self-control appropriate to a city that does not need to prove its status by mob violence.</p>",
"37": "<p>'You have brought these men here, though they have neither robbed temples (hierosylous — temple robbers) nor blasphemed our goddess (blasphēmountas tēn theon hymōn)' — the clerk's formal legal exoneration: the two capital religious offenses — temple robbery and blasphemy of the deity — cannot be charged against Gaius and Aristarchus. This is the Roman official's implicit assessment: the Christian missionaries have not committed acts that Roman or civic law can prosecute. Paul's consistent legal innocence before Roman authorities (18:15 Gallio; 25:25 Festus; 26:31-32 Agrippa) is a pattern Luke documents across Acts.</p>",
"38": "<p>'If Demetrius and his fellow craftsmen have a grievance (logon — a matter/case; disp=3 for logos) against anybody, the courts are open and there are proconsuls' — logos here (disp=3) is the 'reason/matter/case' sense — not the Johannine Word or the gospel proclamation but the legal cause-of-action (logos = 'a matter to settle'). 'The courts are open' (agoraioi agontai — court days are being held) — the regular legal process is available; extra-legal mob action is unnecessary and illegal. The clerk's insistence on proper channels is the voice of Roman order in the face of Greek populism.</p>",
"39": "<p>'If there is anything further you want to bring up, it must be settled in a legal assembly (en tē ennomō ekklēsia — in the lawful/legal assembly)' — ennomō (lawful, within the law) modifies ekklēsia: the proper assembly governed by law and procedure, not the irregular mob-gathering they are currently in. The distinction between this spontaneous mob-assembly and the legitimate civic ekklēsia implicitly categorizes the current gathering as illegal. The term ekklēsia (assembly) is Paul's word for the church — Luke's irony: the mob-assembly is precisely not the lawful assembly that the ekklēsia of Christ represents.</p>",
"40": "<p>'As it is, we are in danger of being charged with rioting (staseōs — sedition/riot) because of what happened today. In that case we would not be able to account for (logon dounai — to give a logos/account; disp=3 for logos) this commotion, since there is no reason for it' — two logos-senses in one verse: logon dounai (to give an account/reason) is the forensic sense — providing a reasoned defense before Roman authority. The clerk's fear is real: unauthorized civic assemblies that degenerate into violence could trigger Roman intervention and the loss of civic self-governance. The gospel's legal innocence has now been established by a pagan city official's pragmatic self-interest.</p>",
"41": "<p>'After he had said this, he dismissed the assembly' — the grammateus's dismissal (apelysen tēn ekklēsian — he released/dismissed the assembly) ends the riot without violence, without charges, and without Paul's arrest. Luke's narrative irony is complete: the most dangerous threat to the Ephesian mission was resolved not by apostolic confrontation but by a city clerk's bureaucratic speech about proper legal procedure. The gospel survives not because Paul was heroic (he was restrained from entering) but because God's preservation works through unlikely instruments — including Roman civic administration.</p>"
}
}

def main():
    existing = load_comm('mkt-original', 'acts')
    merge_comm(existing, ACTS_CH18_19)
    save_comm('mkt-original', 'acts', existing)
    ch18 = len(existing.get('18', {}))
    ch19 = len(existing.get('19', {}))
    print(f'Acts 18: {ch18}/28. Acts 19: {ch19}/41.')

if __name__ == '__main__':
    main()
